1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
62	const CURSED_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const FIRST_INSURANCE_RATE = 0.1;
66	const LOYALTY_DISCOUNT_RATE = 0.2;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const FOLLOWUP_DISCOUNT_RATE = 0.15;
69	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
70	  sword: 100,
71	  amulet: 60,
72	  staff: 80,
73	  potion: 40,
74	  rune: 25,
75	  moonstone: 25,
76	};
77	
78	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const insuranceValue = (item: Item): number =>
88	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
89	
90	const insuranceSum = (items: Item[]): number =>
91	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
92	
93	const basePremium = (item: Item): number =>
94	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
95	
96	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
97	
98	const groupByType = (items: Item[]): Map<string, Item[]> => {
99	  const groups = new Map<string, Item[]>();
100	  for (const item of items) {
101	    const existing = groups.get(item.type) ?? [];
102	    existing.push(item);
103	    groups.set(item.type, existing);
104	  }
105	  return groups;
106	};
107	
108	const sumBasePremiums = (items: Item[]): number =>
109	  items.reduce((sum, item) => sum + basePremium(item), 0);
110	
111	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
112	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
113	
114	const groupTotal = (type: string, group: Item[]): number =>
115	  isCompleteComponentBlock(type, group)
116	    ? COMPONENT_BLOCK_PRICE
117	    : sumBasePremiums(group);
118	
119	const policyBase = (items: Item[]): number =>
120	  Array.from(groupByType(items)).reduce(
121	    (sum, [type, group]) => sum + groupTotal(type, group),
122	    0,
123	  );
124	
125	const perItemSurcharge = (
126	  items: Item[],
127	  predicate: (item: Item) => boolean,
128	  rate: number,
129	): number =>
130	  items.reduce(
131	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
132	    0,
133	  );
134	
135	const isCursed = (item: Item): boolean => item.cursed === true;
136	
137	const isHighlyEnchanted = (item: Item): boolean =>
138	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
139	
140	const firstInsuranceSurcharge = (base: number): number =>
141	  base * FIRST_INSURANCE_RATE;
142	
143	const loyaltyDiscount = (base: number, customer: Customer): number =>
144	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
145	    ? base * LOYALTY_DISCOUNT_RATE
146	    : 0;
147	
148	const followupDiscount = (base: number, quoteIndex: number): number =>
149	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
150	
151	const totalSurcharges = (items: Item[], base: number): number =>
152	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
153	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
154	  firstInsuranceSurcharge(base);
155	
156	const totalDiscounts = (
157	  base: number,
158	  customer: Customer,
159	  quoteIndex: number,
160	): number =>
161	  loyaltyDiscount(base, customer) + followupDiscount(base, quoteIndex);
162	
163	const quotePremium = (
164	  items: Item[],
165	  customer: Customer,
166	  quoteIndex: number,
167	): number => {
168	  const base = policyBase(items);
169	  const adjusted =
170	    base +
171	    totalSurcharges(items, base) -
172	    totalDiscounts(base, customer, quoteIndex);
173	  return Math.ceil(adjusted) + PROCESSING_FEE;
174	};
175	
176	interface Policy {
177	  items: Item[];
178	  remainingCap: number;
179	}
180	
181	interface ScenarioState {
182	  customer: Customer;
183	  policies: Map<number, Policy>;
184	  quoteIndex: number;
185	  stepIndex: number;
186	}
187	
188	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
189	  state.policies.set(state.stepIndex, {
190	    items: step.items,
191	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
192	  });
193	  const premium = quotePremium(step.items, state.customer, state.quoteIndex);
194	  state.quoteIndex += 1;
195	  return { premium };
196	};
197	
198	const reimbursementRate = (item: Item): number =>
199	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
200	    ? HIGH_ENCHANTMENT_CLAIM_RATE
201	    : 1;
202	
203	const damagePayout = (damage: Damage, items: Item[]): number => {
204	  const item = items.find((it) => it.type === damage.itemType) as Item;
205	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
206	};
207	
208	const countByType = (items: { type?: string; itemType?: string }[]): Map<string, number> => {
209	  const counts = new Map<string, number>();
210	  for (const item of items) {
211	    const key = (item.type ?? item.itemType) as string;
212	    counts.set(key, (counts.get(key) ?? 0) + 1);
213	  }
214	  return counts;
215	};
216	
217	const validateDamages = (damages: Damage[], items: Item[]): void => {
218	  const itemCounts = countByType(items);
219	  const damageCounts = countByType(damages);
220	  for (const [type, count] of damageCounts) {
221	    if (count > (itemCounts.get(type) ?? 0)) {
222	      throw new Error(
223	        `claim damages exceed policy coverage for itemType ${type}`,
224	      );
225	    }
226	  }
227	};
228	
229	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
230	  const policy = state.policies.get(step.policy) as Policy;
231	  validateDamages(step.incident.damages, policy.items);
232	  const payout = step.incident.damages.reduce(
233	    (sum, damage) => sum + damagePayout(damage, policy.items),
234	    0,
235	  );
236	  policy.remainingCap -= payout;
237	  return { payout, remainingCap: policy.remainingCap };
238	};
239	
240	const processStep = (step: Step, state: ScenarioState): StepResult =>
241	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
242	
243	export const processScenario = (scenario: Scenario): ScenarioOutput => {
244	  const state: ScenarioState = {
245	    customer: scenario.customer,
246	    policies: new Map<number, Policy>(),
247	    quoteIndex: 0,
248	    stepIndex: 0,
249	  };
250	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
251	    state.stepIndex = stepIndex;
252	    return processStep(step, state);
253	  });
254	  return { results };
255	};
